from dotenv import load_dotenv

load_dotenv()

class Config:
    """配置管理"""

    def __init__(self):
        self.bot_token = os.getenv("TELEGRAM_BOT_TOKEN", "")
        self.admin_ids = self._parse_admin_ids(os.getenv("ADMIN_IDS", ""))
        self.log_level = os.getenv("LOG_LEVEL", "INFO")

    def _parse_admin_ids(self, ids_str: str) -> list:
        if not ids_str:
            return []
        try:
            return [int(x.strip()) for x in ids_str.split(",")]
        except ValueError:
            return []",
