    "content": "import psutil
from datetime import datetime

def get_cpu_percent() -> float:
    """获取 CPU 使用率"""
    return psutil.cpu_percent(interval=1)

def get_memory_info() -> dict:
    """获取内存信息"""
    mem = psutil.virtual_memory()
    return {
        "total": mem.total / (1024 ** 3),  # GB
        "used": mem.used / (1024 ** 3),    # GB
        "percent": mem.percent
    }

def get_system_report() -> str:
    """获取系统资源报告"""
    cpu = get_cpu_percent()
    memory = get_memory_info()

    # CPU 状态图标
    if cpu < 50:
        cpu_icon = "🟢"
    elif cpu < 80:
        cpu_icon = "🟡"
    else:
        cpu_icon = "🔴"

    # 内存状态图标
    if memory["percent"] < 50:
        mem_icon = "🟢"
    elif memory["percent"] < 80:
        mem_icon = "🟡"
    else:
        mem_icon = "🔴"

    report = f"""
🖥️ **系统资源报告**

{cpu_icon} **CPU 使用率**: {cpu:.1f}%
🟢 系统运行正常

{mem_icon} **内存使用**: {memory['used']:.2f} GB / {memory['total']:.2f} GB
📊 使用率：{memory['percent']:.1f}%

⏰ 更新时间：{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}
"""
    return report",
